      restoreGraphViewProviderState: vi.fn(() => createRestoredState()),
    }));
    vi.doMock('../../../../src/extension/repoSettings/meta', () => ({
      readCodeGraphyRepoMeta: vi.fn(() => ({
        pendingChangedFiles: ['src/a.ts', 'src/b.ts'],
